static void test_close_source_tcp_send_segment_success_tv001(void) {
    Topology *sim_topo = topology_create();
    assert(sim_topo != NULL);
    Scheduler *sim_sched = scheduler_create(64);
    assert(sim_sched != NULL);
    Simulator *sim = simulator_create(sim_topo, sim_sched);
    assert(sim != NULL);
    Tcb tcb;
    memset(&tcb, 0, sizeof(tcb));
    tcb.valid = 1;
    (&tcb)->valid = 1;
    (&tcb)->state = TCP_ESTABLISHED;
    if ((&tcb)->local_ip == 0) (&tcb)->local_ip = 1;
    if ((&tcb)->remote_ip == 0) (&tcb)->remote_ip = 1;
    Device kleva_success_dev;
    memset(&kleva_success_dev, 0, sizeof(kleva_success_dev));
    Interface kleva_success_iface;
    memset(&kleva_success_iface, 0, sizeof(kleva_success_iface));
    Interface kleva_success_peer;
    memset(&kleva_success_peer, 0, sizeof(kleva_success_peer));
    Interface *kleva_success_ifaces[1] = {&kleva_success_iface};
    Link kleva_success_link;
    memset(&kleva_success_link, 0, sizeof(kleva_success_link));
    ArpCache kleva_success_arp;
    memset(&kleva_success_arp, 0, sizeof(kleva_success_arp));
    if ((sim)->topo) { (sim)->topo->devices[0] = &kleva_success_dev; (sim)->topo->dev_count = 1; }
    kleva_success_dev.interfaces = kleva_success_ifaces;
    kleva_success_dev.iface_count = 1;
    kleva_success_dev.iface_max = 1;
    kleva_success_iface.ip_addr = ns_htonl((&tcb)->local_ip);
    kleva_success_iface.prefix_len = 0;
    kleva_success_iface.up = 1;
    kleva_success_iface.device = &kleva_success_dev;
    kleva_success_iface.link = &kleva_success_link;
    kleva_success_iface.arp_cache = &kleva_success_arp;
    kleva_success_peer.up = 1;
    kleva_success_link.end_a = &kleva_success_iface;
    kleva_success_link.end_b = &kleva_success_peer;
    kleva_success_link.up = 1;
    kleva_success_arp.entries[0].valid = 1;
    kleva_success_arp.entries[0].ip_addr = (&tcb)->remote_ip;
    memset(kleva_success_arp.entries[0].mac_addr, 0xA5, sizeof(kleva_success_arp.entries[0].mac_addr));
    tcp_close(sim, &tcb);
    int out_sim_topo_nonnull = (sim->topo != NULL);
    int out_sim_sched_nonnull = (sim->sched != NULL);
    uint64_t out_sim_end_time = sim->end_time;
    uint32_t out_tcb_local_ip = tcb.local_ip;
    uint32_t out_tcb_remote_ip = tcb.remote_ip;
    uint16_t out_tcb_local_port = tcb.local_port;
    uint16_t out_tcb_remote_port = tcb.remote_port;
    int out_tcb_state = tcb.state;
    uint32_t out_tcb_snd_una = tcb.snd_una;
    uint32_t out_tcb_snd_nxt = tcb.snd_nxt;
    uint32_t out_tcb_rcv_nxt = tcb.rcv_nxt;
    uint16_t out_tcb_rcv_wnd = tcb.rcv_wnd;
    uint16_t out_tcb_snd_wnd = tcb.snd_wnd;
    int out_tcb_sendq_count = tcb.sendq.count;
    uint64_t out_tcb_retransmit_ts = tcb.retransmit_ts;
    int out_tcb_recv_handler_nonnull = (tcb.recv_handler != NULL);
    int out_tcb_connect_handler_nonnull = (tcb.connect_handler != NULL);
    int out_tcb_handler_ctx_nonnull = (tcb.handler_ctx != NULL);
    int out_tcb_valid = tcb.valid;
    assert(out_sim_topo_nonnull == 1); /* EVA-proven oracle */
    assert(out_sim_sched_nonnull == 1); /* EVA-proven oracle */
    assert(out_sim_end_time == 0); /* EVA-proven oracle */
    assert(out_tcb_local_ip == 1); /* EVA-proven oracle */
    assert(out_tcb_remote_ip == 1); /* EVA-proven oracle */
    assert(out_tcb_local_port == 0); /* EVA-proven oracle */
    assert(out_tcb_remote_port == 0); /* EVA-proven oracle */
    assert(out_tcb_state == 5); /* EVA-proven oracle */
    assert(out_tcb_snd_una == 0); /* EVA-proven oracle */
    assert(out_tcb_snd_nxt == 1); /* EVA-proven oracle */
    assert(out_tcb_rcv_nxt == 0); /* EVA-proven oracle */
    assert(out_tcb_rcv_wnd == 0); /* EVA-proven oracle */
    assert(out_tcb_snd_wnd == 0); /* EVA-proven oracle */
    assert(out_tcb_sendq_count == 1); /* EVA-proven oracle */
    assert(out_tcb_retransmit_ts == 1000000); /* EVA-proven oracle */
    assert(out_tcb_recv_handler_nonnull == 0); /* EVA-proven oracle */
    assert(out_tcb_connect_handler_nonnull == 0); /* EVA-proven oracle */
    assert(out_tcb_handler_ctx_nonnull == 0); /* EVA-proven oracle */
    assert(out_tcb_valid == 1); /* EVA-proven oracle */
    printf("PASS test_close_source_tcp_send_segment_success_tv001\n");
}

